-- =========================================================
-- MINIMAL STANDALONE SCHEMA FOR RECURSIVE CTE ENGINE
-- =========================================================

DROP TABLE IF EXISTS piece_bitboards;

CREATE TABLE piece_bitboards(piece TINYINT PRIMARY KEY, bitboard UBIGINT);


DROP TABLE IF EXISTS piece_masks;

CREATE TABLE piece_masks (
            piece TINYINT PRIMARY KEY,
            mask_wK UBIGINT, mask_wQ UBIGINT, mask_wR UBIGINT, mask_wB UBIGINT, mask_wN UBIGINT, mask_wP UBIGINT,
            mask_bK UBIGINT, mask_bQ UBIGINT, mask_bR UBIGINT, mask_bB UBIGINT, mask_bN UBIGINT, mask_bP UBIGINT
        );


DROP TABLE IF EXISTS game_state;

CREATE TABLE game_state(
            active_turn TINYINT,
            castling_rights HUGEINT,
            halfmove_clock INTEGER,
            fullmove_number INTEGER
        );

        VALUES (1, 15, 0, 1);

DROP TABLE IF EXISTS v_board_state;

CREATE TABLE v_board_state (
            wK_bb UBIGINT, wQ_bb UBIGINT, wR_bb UBIGINT, wB_bb UBIGINT, wN_bb UBIGINT, wP_bb UBIGINT,
            bK_bb UBIGINT, bQ_bb UBIGINT, bR_bb UBIGINT, bB_bb UBIGINT, bN_bb UBIGINT, bP_bb UBIGINT,
            castling_rights HUGEINT, active_turn TINYINT
        );

DROP TABLE IF EXISTS pst_values;

CREATE TABLE pst_values (piece TINYINT, square TINYINT, value INTEGER, PRIMARY KEY(piece, square));


DROP TABLE IF EXISTS zobrist_constants;

CREATE TABLE zobrist_constants (piece TINYINT, square TINYINT, val UBIGINT, PRIMARY KEY(piece, square));


DROP TABLE IF EXISTS zobrist_misc;

CREATE TABLE zobrist_misc (type VARCHAR, idx TINYINT, val UBIGINT);


DROP TABLE IF EXISTS squares;

CREATE TABLE squares (i TINYINT PRIMARY KEY);


DROP SEQUENCE IF EXISTS seq_search_tree_id;

CREATE SEQUENCE seq_search_tree_id START WITH 1;

DROP TABLE IF EXISTS mobility_precomputed;

CREATE TABLE mobility_precomputed (piece TINYINT, from_sq TINYINT, target_sq TINYINT, ray_mask UBIGINT);

CREATE INDEX idx_mobility_target ON mobility_precomputed(target_sq);

CREATE INDEX idx_mobility_from_piece ON mobility_precomputed(piece, from_sq);

DROP TABLE IF EXISTS attacks_precomputed;

CREATE TABLE attacks_precomputed (square TINYINT PRIMARY KEY, knight_mask UBIGINT, king_mask UBIGINT, white_pawn_mask UBIGINT, black_pawn_mask UBIGINT);

-- =========================================================
-- GENERATED PRECOMPUTED TABLES
-- =========================================================



-- =========================================================
-- BOARD STATE POPULATION HELPER
-- =========================================================

        SELECT 
            COALESCE((SELECT bitboard FROM piece_bitboards WHERE piece = 6), 0::UBIGINT) as wK_bb,
            COALESCE((SELECT bitboard FROM piece_bitboards WHERE piece = 5), 0::UBIGINT) as wQ_bb,
            COALESCE((SELECT bitboard FROM piece_bitboards WHERE piece = 4), 0::UBIGINT) as wR_bb,
            COALESCE((SELECT bitboard FROM piece_bitboards WHERE piece = 3), 0::UBIGINT) as wB_bb,
            COALESCE((SELECT bitboard FROM piece_bitboards WHERE piece = 2), 0::UBIGINT) as wN_bb,
            COALESCE((SELECT bitboard FROM piece_bitboards WHERE piece = 1), 0::UBIGINT) as wP_bb,
            COALESCE((SELECT bitboard FROM piece_bitboards WHERE piece = -6), 0::UBIGINT) as bK_bb,
            COALESCE((SELECT bitboard FROM piece_bitboards WHERE piece = -5), 0::UBIGINT) as bQ_bb,
            COALESCE((SELECT bitboard FROM piece_bitboards WHERE piece = -4), 0::UBIGINT) as bR_bb,
            COALESCE((SELECT bitboard FROM piece_bitboards WHERE piece = -3), 0::UBIGINT) as bB_bb,
            COALESCE((SELECT bitboard FROM piece_bitboards WHERE piece = -2), 0::UBIGINT) as bN_bb,
            COALESCE((SELECT bitboard FROM piece_bitboards WHERE piece = -1), 0::UBIGINT) as bP_bb,
            COALESCE((SELECT castling_rights FROM game_state ORDER BY fullmove_number DESC, halfmove_clock DESC LIMIT 1), 0::HUGEINT) as castling_rights,
            COALESCE((SELECT active_turn FROM game_state ORDER BY fullmove_number DESC, halfmove_clock DESC LIMIT 1), 1::TINYINT) as active_turn;;
